// // This module decrements a 32-bit binary counter on the falling edge of the clock signal and resets to maximum value when the reset signal is deasserted.
module counter_32bit (  
    input clk,  
    input reset,  
    input enable,  
    output reg [31:0] count  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            count <= 32'b0;  
        end else if (enable) begin  
            count <= count + 1;  
        end  
    end  
endmodule
